from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of triples about astronauts (or related entities) into a
    fluent English sentence.  The function groups triples by their subject and
    builds a clause for each predicate, then joins the clauses into a single
    (or a few) readable sentences.
    """
    if not triples:
        return ""

    # Helper to turn a predicate/object pair into a descriptor (without repeating the subject)
    def phrase(subj: str, pred: str, obj: str) -> str:
        """Return a natural‑language descriptor for a single predicate."""
        obj = obj.strip().strip('"')
        p = pred.lower().replace(" ", "")
        def fmt_date(d: str) -> str:
            try:
                from datetime import datetime
                dt = datetime.strptime(d, "%Y-%m-%d")
                return dt.strftime("%B %-d, %Y")
            except Exception:
                return d

        if p == "birthdate":
            return f"was born on {fmt_date(obj)}"
        if p == "birthplace":
            return f"was born in {obj}"
        if p == "deathdate":
            return f"died on {fmt_date(obj)}"
        if p == "deathplace":
            return f"died in {obj}"
        if p == "nationality":
            low_obj = obj.lower()
            # Convert common country names to adjective forms
            if low_obj in ("united states", "usa", "united states of america"):
                return f"was an American"
            # Simple heuristic: add 'was a' before the country adjective
            adj = obj.strip().title()
            # If the adjective already looks like an adjective (ends with 'ian', 'ese', etc.), keep it
            if adj.endswith(("ian", "ese", "ish", "an", "ic")):
                return f"was a {adj}"
            return f"was from {adj}"
        if p == "occupation":
            return f"was a {obj.lower()}"
        if p == "status":
            low = obj.lower()
            if low == "retired":
                return "is retired"
            return f"is {low}"
        if p == "selectedbynasa":
            return f"was selected by NASA in {obj}"
        if p == "mission":
            # Assume subject is an astronaut; describe crew membership in the mission
            return f"was a crew member of {obj}"
        if p == "timeinspace":
            try:
                mins = float(obj)
                hrs = int(mins // 60)
                rem = int(mins % 60)
                if hrs:
                    return f"spent {hrs} hour{'s' if hrs>1 else ''}" + (f" and {rem} minute{'s' if rem!=1 else ''}" if rem else "") + " in space"
                else:
                    return f"spent {rem} minute{'s' if rem!=1 else ''} in space"
            except Exception:
                return f"spent {obj} minutes in space"
        if p == "title":
            return f"held the title of {obj}"
        if p == "award":
            return f"received the {obj}"
        if p == "awards":
            return f"received {obj} awards"
        if p == "ribbonaward":
            return f"was awarded the {obj}"
        if p == "operator":
            return f"operated by {obj}"
        if p == "commander":
            return f"{obj} was the commander of {subj}"
        if p == "backuppilot":
            # Handled in aggregation step; fallback for isolated cases
            return f"{subj}'s backup pilot was {obj}"
        if p == "crewmembers":
            # Handled in aggregation step; fallback for isolated cases
            return f"{obj} was a crew member of {subj}"
        if p == "leader":
            # Subject is an entity, object is a person
            return f"{obj} is the leader of {subj}"
        if p == "representative":
            return f"{obj} was the representative of {subj}"
        if p == "alternativename":
            return f"is also known as {obj}"
        if p == "servedaschiefoftheastronautofficein":
            return f"served as Chief of the Astronaut Office in {obj}"
        if p == "bird":
            return f"The {obj.lower()} is a bird found in {subj}"
        # Generic fallback
        return f"is {obj}"

    # ------------------------------------------------------------
    # First, handle mission‑centric relations to produce richer
    # combined sentences (crew members, backup pilot, commander, etc.)
    # ------------------------------------------------------------
    from collections import defaultdict

    # Aggregate crew members for each mission from both directions
    mission_to_astronauts: dict[str, list[str]] = defaultdict(list)
    mission_to_backup: dict[str, str] = {}
    mission_to_commander: dict[str, str] = {}

    remaining_triples: list[Triple] = []

    for t in triples:
        pred = t.predicate.lower().replace(" ", "")
        if pred == "mission":
            # subject is astronaut, object is mission
            mission_to_astronauts[t.object].append(t.subject)
            continue
        if pred == "crewmembers":
            # subject is mission, object is astronaut
            mission_to_astronauts[t.subject].append(t.object)
            continue
        if pred == "backuppilot":
            mission_to_backup[t.subject] = t.object
            continue
        if pred == "commander":
            mission_to_commander[t.subject] = t.object
            continue
        # keep triples that are not handled above
        remaining_triples.append(t)

    # Build sentences for aggregated mission information
    aggregated_sentences: list[str] = []

    for mission, astronauts in mission_to_astronauts.items():
        if not astronauts:
            continue
        # format list of names
        if len(astronauts) == 1:
            crew_part = f"{astronauts[0]} was a crew member of {mission}"
        else:
            names = ", ".join(astronauts[:-1]) + f", and {astronauts[-1]}"
            crew_part = f"{names} were crew members of {mission}"
        aggregated_sentences.append(crew_part + ".")

    for mission, backup in mission_to_backup.items():
        aggregated_sentences.append(f"{mission}'s backup pilot was {backup}.")

    for mission, commander in mission_to_commander.items():
        aggregated_sentences.append(f"{mission}'s commander was {commander}.")

    # ------------------------------------------------------------
    # Now group the remaining triples by subject as before
    # ------------------------------------------------------------
    groups = defaultdict(list)
    for t in remaining_triples:
        groups[t.subject].append(t)

    # ------------------------------------------------------------
    # Generate sentences for the remaining groups
    # ------------------------------------------------------------

    sentences = []
    for subj, items in groups.items():
        raw_descriptors = [phrase(subj, t.predicate, t.object) for t in items]
        if not raw_descriptors:
            continue

        # Separate possible nationality adjective (single word, title‑cased) from other clauses
        nationality_adj = None
        descriptors = []
        for d in raw_descriptors:
            if nationality_adj is None and d.isalpha() and d.istitle():
                nationality_adj = d
            else:
                descriptors.append(d)

        if nationality_adj:
            # Build sentence starting with the adjective
            if not descriptors:
                sent = f"The {nationality_adj} {subj}."
            elif len(descriptors) == 1:
                sent = f"The {nationality_adj} {subj} {descriptors[0]}."
            else:
                body = ", ".join(descriptors[:-1])
                sent = f"The {nationality_adj} {subj} {body}, and {descriptors[-1]}."
        else:
            if len(descriptors) == 1:
                sent = f"{subj} {descriptors[0]}."
            else:
                body = ", ".join(descriptors[:-1])
                sent = f"{subj} {body}, and {descriptors[-1]}."
        sentences.append(sent)

    # Combine sentences for different subjects and prepend any aggregated mission sentences
    all_sentences = sentences + aggregated_sentences
    return " ".join(all_sentences)

